INSERT INTO resources (name, category_id, subcategory, description, address, city, county, state, zip_code, phone, website, hours, accepts_uninsured, sliding_scale, medicaid, medicare, private_insurance, walk_ins_welcome, appointments, telehealth, cost_free, cost_estimate_min, cost_estimate_max, languages, accessibility, services, specialties, audiences, rating, photo_url, source) VALUES
('988 Suicide & Crisis Lifeline - Washington', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'Free, confidential 24/7 suicide and crisis lifeline providing support for people in distress, including prevention and crisis resources. Dedicated line available for American Indian and Alaska Native communities.', '', 'Statewide', '', 'WA', '', '988', 'https://988lifeline.org', '{"mon":"24hours","tue":"24hours","wed":"24hours","thu":"24hours","fri":"24hours","sat":"24hours","sun":"24hours"}', true, false, false, false, false, true, true, true, true, 0, 0, ARRAY['English','Spanish'], ARRAY['TTY','interpreter services'], ARRAY['crisis support','suicide prevention','emotional support'], ARRAY['crisis intervention'], ARRAY['general public'], 0, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb=w=800', 'verified'),
('Crisis Connections - King County', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'Nonprofit agency providing 24/7 crisis line services including King County 988, WA Recovery Help Line, Teen Link, WA Warm Line, and King County 2-1-1 community resources.', '1900 Queen Anne Ave N Ste 210', 'Seattle', 'King', 'WA', '98109', '866-427-4747', 'https://www.crisisconnections.org', '{"mon":"24hours","tue":"24hours","wed":"24hours","thu":"24hours","fri":"24hours","sat":"24hours","sun":"24hours"}', true, false, false, false, false, true, true, true, true, 0, 0, ARRAY['English','Spanish'], ARRAY['TTY','interpreter services'], ARRAY['crisis line','suicide prevention','recovery help line','teen line','warm line','211'], ARRAY['crisis intervention'], ARRAY['general public','youth'], 0, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb=w=800', 'verified'),
('Teen Link', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'Anonymous and confidential help line for youth, answered by teen volunteers. Available every evening from 6-10pm via phone and chat. Also provides youth suicide prevention trainings in schools.', '1900 Queen Anne Ave N Ste 210', 'Seattle', 'King', 'WA', '98109', '866-833-6546', 'https://www.crisisconnections.org/programs/teen-link', '{"mon":"18:00-22:00","tue":"18:00-22:00","wed":"18:00-22:00","thu":"18:00-22:00","fri":"18:00-22:00","sat":"18:00-22:00","sun":"18:00-22:00"}', true, false, false, false, false, true, true, true, true, 0, 0, ARRAY['English','Spanish'], ARRAY['interpreter services'], ARRAY['youth crisis line','suicide prevention','peer support'], ARRAY['crisis intervention'], ARRAY['youth','teens'], 0, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb=w=800', 'verified'),
('WA Recovery Help Line', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', 'Statewide resource for people struggling with mental health, substance abuse, or problem gambling. Available 24/7, free and confidential.', '1900 Queen Anne Ave N Ste 210', 'Seattle', 'King', 'WA', '98109', '866-789-1511', 'https://www.warecoveryhelpline.org', '{"mon":"24hours","tue":"24hours","wed":"24hours","thu":"24hours","fri":"24hours","sat":"24hours","sun":"24hours"}', true, false, false, false, false, true, true, true, true, 0, 0, ARRAY['English','Spanish'], ARRAY['TTY','interpreter services'], ARRAY['substance use support','mental health support','problem gambling support','referrals'], ARRAY['crisis intervention','substance use'], ARRAY['general public'], 0, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb=w=800', 'verified'),
('National Domestic Violence Hotline - Washington', (SELECT id FROM resource_categories WHERE slug='crisis-line'), '', '24/7 free and confidential support for anyone experiencing domestic violence or questioning their relationship. Available by phone, chat, or text.', '', 'Statewide', '', 'WA', '', '800-799-7233', 'https://www.thehotline.org', '{"mon":"24hours","tue":"24hours","wed":"24hours","thu":"24hours","fri":"24hours","sat":"24hours","sun":"24hours"}', true, false, false, false, false, true, true, true, true, 0, 0, ARRAY['English','Spanish'], ARRAY['TTY'], ARRAY['crisis support','safety planning','advocacy','referrals'], ARRAY['crisis intervention','domestic violence'], ARRAY['survivors of abuse'], 0, 'https://images.pexels.com/photos/4149199/pexels-photo-4149199.jpeg?auto=compress&cs=tinysrgb=w=800', 'verified'),
('Northwest Harvest - SODO Community Market', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'No-cost grocery store providing free food to anyone in need, including a baby cupboard, food bag program, and limited supply of pet food and diapers. No ID or proof of income required.', '1915 4th Ave S', 'Seattle', 'King', 'WA', '98134', '206-625-0755', 'https://www.northwestharvest.org', '{"mon":"13:30-19:30","tue":"Closed","wed":"8:00-14:00","thu":"Closed","fri":"8:00-14:00","sat":"Closed","sun":"Closed"}', true, false, false, false, false, true, false, false, true, 0, 0, ARRAY['English','Spanish','Vietnamese','Somali'], ARRAY['wheelchair','ADA parking'], ARRAY['food pantry','baby cupboard','pet food','diapers'], ARRAY['food bank'], ARRAY['general public'], 0, 'https://images.pexels.com/photos/6192363/pexels-photo-6192363.jpeg?auto=compress&cs=tinysrgb=w=800', 'verified'),
('Food Lifeline', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'Regional food bank distributing food to over 300 food banks, shelters, and meal programs across 17 western Washington counties. Accepts food donations and coordinates distribution.', '815 S 96th St', 'Seattle', 'King', 'WA', '98108', '206-545-6600', 'https://foodlifeline.org', '{"mon":"8:00-16:00","tue":"8:00-16:00","wed":"8:00-16:00","thu":"8:00-16:00","fri":"8:00-16:00","sat":"Closed","sun":"Closed"}', true, false, false, false, false, true, false, false, true, 0, 0, ARRAY['English','Spanish'], ARRAY['wheelchair','ADA parking'], ARRAY['food distribution','food bank network','food donations'], ARRAY['food bank'], ARRAY['general public'], 0, 'https://images.pexels.com/photos/6192363/pexels-photo-6192363.jpeg?auto=compress&cs=tinysrgb=w=800', 'verified'),
('Second Harvest Inland Northwest', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'Regional food bank serving eastern Washington and north Idaho, distributing millions of pounds of food to partner food pantries, meal sites, and hunger relief programs.', '915 E Trent Ave', 'Spokane', 'Spokane', 'WA', '99202', '509-252-6246', 'https://www.2-harvest.org', '{"mon":"8:00-16:00","tue":"8:00-16:00","wed":"8:00-16:00","thu":"8:00-16:00","fri":"8:00-16:00","sat":"Closed","sun":"Closed"}', true, false, false, false, false, true, false, false, true, 0, 0, ARRAY['English','Spanish'], ARRAY['wheelchair','ADA parking'], ARRAY['food distribution','food bank network','mobile food bank'], ARRAY['food bank'], ARRAY['general public'], 0, 'https://images.pexels.com/photos/6192363/pexels-photo-6192363.jpeg?auto=compress&cs=tinysrgb=w=800', 'verified'),
('Caritas Food Bank', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'Community food bank in Spokane providing free food to individuals and families in need, open multiple days per week.', '1228 W Nebraska Ave', 'Spokane', 'Spokane', 'WA', '99205', '509-326-2241', 'https://www.caritaspokane.org', '{"mon":"10:30-13:30","tue":"Closed","wed":"10:30-13:30","thu":"10:30-13:30","fri":"Closed","sat":"Closed","sun":"Closed"}', true, false, false, false, false, true, false, false, true, 0, 0, ARRAY['English','Spanish'], ARRAY['wheelchair','ADA parking'], ARRAY['food pantry','emergency food'], ARRAY['food bank'], ARRAY['general public'], 0, 'https://images.pexels.com/photos/6192363/pexels-photo-6192363.jpeg?auto=compress&cs=tinysrgb=w=800', 'verified'),
