('Clark County Food Bank', (SELECT id FROM resource_categories WHERE slug='food-bank'), '', 'Regional food bank serving Clark County, distributing food to partner pantries, meal programs, and food assistance sites throughout the community.', '6502 NE 47th Ave', 'Vancouver', 'Clark', 'WA', '98661', '360-693-0939', 'https://clarkcountyfoodbank.org', '{"mon":"8:00-16:00","tue":"8:00-16:00","wed":"8:00-16:00","thu":"8:00-16:00","fri":"8:00-16:00","sat":"Closed","sun":"Closed"}', true, false, false, false, false, true, false, false, true, 0, 0, ARRAY['English','Spanish','Russian'], ARRAY['wheelchair','ADA parking'], ARRAY['food distribution','food pantry network','mobile pantry'], ARRAY['food bank'], ARRAY['general public'], 0, 'https://images.pexels.com/photos/6192363/pexels-photo-6192363.jpeg?auto=compress&cs=tinysrgb=w=800', 'verified')
